<template><div><PageHeader eyebrow="ADMIN" title="系统概览" description="管理平台业务数据、内容审核与服务运行状态"/><div class="metric-grid"><div v-for="m in metrics" :key="m.label" class="metric-card"><span>{{ m.label }}</span><strong>{{ m.value }}</strong><small>{{ m.note }}</small></div></div><div class="admin-link-grid"><router-link v-for="item in links" :key="item.path" :to="item.path" class="admin-link"><span>{{ item.icon }}</span><div><h3>{{ item.title }}</h3><p>{{ item.desc }}</p></div></router-link></div></div></template>
<script setup>import { onMounted,ref } from 'vue';import PageHeader from '../../components/PageHeader.vue';import { workApi } from '../../api/work';import { characterApi } from '../../api/character';import { personApi } from '../../api/person';import { userApi } from '../../api/user';import { normalizePage } from '../../utils/page';const metrics=ref([{label:'注册用户',value:'—',note:'auth-service'},{label:'作品数量',value:'—',note:'work-service'},{label:'角色数量',value:'—',note:'character-service'},{label:'人物数量',value:'—',note:'person-service'}]);const links=[{path:'/admin/users',icon:'◎',title:'用户管理',desc:'封禁、角色与密码重置'},{path:'/admin/content',icon:'▣',title:'内容管理',desc:'作品、角色、人物和分类'},{path:'/admin/relations',icon:'⌘',title:'关系管理',desc:'分类、角色与人物关联'},{path:'/admin/comments',icon:'✦',title:'评论审核',desc:'待审核、置顶与精华'},{path:'/admin/notifications',icon:'◉',title:'通知管理',desc:'定向通知与系统广播'},{path:'/admin/chats',icon:'◇',title:'聊天治理',desc:'会话、消息和治理日志'},{path:'/admin/health',icon:'✓',title:'服务状态',desc:'检查微服务运行状态'}];onMounted(async()=>{const rs=await Promise.allSettled([userApi.adminPage({page:0,size:1}),workApi.page({current:1,size:1}),characterApi.page({current:1,size:1}),personApi.page({current:1,size:1})]);rs.forEach((r,i)=>{if(r.status==='fulfilled')metrics.value[i].value=normalizePage(r.value).total})})</script>
